/**
 * Espera un tiempo específico en milisegundos.
 *
 * @param ms - Tiempo de espera en milisegundos. Por defecto es 2000ms (2 segundos).
 * @returns Una promesa que se resuelve después del tiempo especificado.
 *
 * @example
 * // Esperar 2 segundos (valor predeterminado)
 * await wait();
 *
 * @example
 * // Esperar 5 segundos
 * await wait(5000);
 *
 * @example
 * // Uso con then()
 * wait(1000).then(() => console.log('Ha pasado 1 segundo'));
 */
export declare function wait(ms?: number): Promise<void>;
export default wait;
